// Process Lead Data - Normalize and generate slug
const items = $input.all();
const results = [];

for (const item of items) {
  const companyName = (item.json['Company Name'] || '').trim();
  const email = (item.json['Contact Email'] || '').trim().toLowerCase();
  const industry = item.json['Industry'] || 'Other';
  const rawBudget = (item.json['Estimated Budget'] || '0').toString().replace(/[^0-9.]/g, '');
  const budget = parseFloat(rawBudget) || 0;
  const needs = (item.json['Needs Description'] || '').trim();

  // Generate company slug
  const slug = companyName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

  // Extract email domain
  const emailDomain = email.split('@')[1] || '';

  results.push({
    json: {
      companyName,
      companySlug: slug,
      contactEmail: email,
      emailDomain,
      industry,
      budget,
      budgetFormatted: `$${budget.toLocaleString('en-US', { minimumFractionDigits: 2 })}`,
      budgetTier: budget >= 100000 ? 'Enterprise' : budget >= 25000 ? 'Mid-Market' : 'SMB',
      needs,
      capturedAt: new Date().toISOString(),
      leadId: `LEAD-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`
    }
  });
}

return results;

// Parse AI Scoring - Extract structured scoring data
const items = $input.all();
const results = [];

for (const item of items) {
  const aiText = item.json.text || item.json.response || JSON.stringify(item.json);
  let scoring = {};

  try {
    const jsonMatch = aiText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      scoring = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    scoring = {
      leadScore: 50,
      purchaseIntent: 'medium',
      buyerPersona: 'Unknown',
      painPoints: ['Unable to parse AI response'],
      recommendedActions: ['Manual qualification required'],
      competitivePosition: 'Unknown',
      dealProbability: 50,
      estimatedDealSize: 'Unknown',
      summary: 'AI scoring could not be parsed. Manual review required.'
    };
  }

  const leadScore = parseInt(scoring.leadScore) || 50;
  const isHotLead = leadScore >= 70;
  const leadData = $('Process Lead Data').first().json;

  results.push({
    json: {
      ...leadData,
      leadScore,
      isHotLead,
      leadGrade: leadScore >= 80 ? 'A' : leadScore >= 60 ? 'B' : leadScore >= 40 ? 'C' : 'D',
      purchaseIntent: scoring.purchaseIntent || 'medium',
      buyerPersona: scoring.buyerPersona || 'Unknown',
      painPoints: scoring.painPoints || [],
      recommendedActions: scoring.recommendedActions || [],
      competitivePosition: scoring.competitivePosition || 'Unknown',
      dealProbability: scoring.dealProbability || 50,
      estimatedDealSize: scoring.estimatedDealSize || 'Unknown',
      aiSummary: scoring.summary || 'No summary available',
      scoredAt: new Date().toISOString()
    }
  });
}

return results;

